import { Suspense } from 'react'
import { TransactionsTable } from '@/components/financial/TransactionsTable'
import { getTransactions } from '@/actions/financial'
// import TransactionForm from '@/components/financial/TransactionForm' 

export default async function FinancialTransactionsPage() {
    const initialTransactions = await getTransactions(undefined, undefined, 50); // Get last 50 transactions

    return (
        <div className="flex flex-col h-full space-y-4">
            <div className="flex justify-between items-center p-4">
                <h1 className="text-2xl font-bold tracking-tight">Transações</h1>
                {/* <TransactionForm /> */}
            </div>
            <div className="flex-1 p-4">
                <Suspense fallback={<div>Carregando transações...</div>}>
                    <TransactionsTable initialData={initialTransactions} />
                </Suspense>
            </div>
        </div>
    )
}
